const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function chargePayment(message) {
  const {
    paymentId,
    amount,
    currency,
    customerId,
    source,
    metadata = {}
  } = message;

  console.log(`[PAYMENT] Charging paymentId=${paymentId} customerId=${customerId} amount=${amount} ${currency} source=${source}`);
  await simulateAsyncWork(300);
  console.log(`[PAYMENT] Charge successful for paymentId=${paymentId}`, metadata);
}

async function refundPayment(message) {
  const {
    paymentId,
    refundId,
    amount,
    currency,
    reason,
    metadata = {}
  } = message;

  console.log(`[PAYMENT] Refunding paymentId=${paymentId} refundId=${refundId} amount=${amount} ${currency} reason=${reason}`);
  await simulateAsyncWork(300);
  console.log(`[PAYMENT] Refund successful for refundId=${refundId}`, metadata);
}

async function voidPayment(message) {
  const {
    paymentId,
    authorizationId,
    metadata = {}
  } = message;

  console.log(`[PAYMENT] Voiding paymentId=${paymentId} authorizationId=${authorizationId}`);
  await simulateAsyncWork(300);
  console.log(`[PAYMENT] Void successful for paymentId=${paymentId}`, metadata);
}

async function processPaymentEvent(event) {
  switch (event.type) {
    case 'payment.charge':
      await chargePayment(event);
      break;
    case 'payment.refund':
      await refundPayment(event);
      break;
    case 'payment.void':
      await voidPayment(event);
      break;
    default:
      throw new Error(`Unsupported payment event type: ${event.type}`);
  }
}

function simulateAsyncWork(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, {
    durable: true
  });

  await channel.prefetch(PREFETCH);

  console.log(`[RABBITMQ] Connected to ${RABBITMQ_URL}`);
  console.log(`[RABBITMQ] Waiting for messages on queue "${QUEUE_NAME}"`);

  const shutdown = async () => {
    console.log('[SYSTEM] Shutting down...');
    try {
      await channel.close();
    } catch (_) {}
    try {
      await connection.close();
    } catch (_) {}
    process.exit(0);
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);

  channel.consume(
    QUEUE_NAME,
    async msg => {
      if (!msg) return;

      try {
        const raw = msg.content.toString('utf8');
        const event = JSON.parse(raw);

        console.log('[RABBITMQ] Received message:', event);

        await processPaymentEvent(event);

        channel.ack(msg);
      } catch (err) {
        console.error('[ERROR] Failed to process payment event:', err);
        channel.nack(msg, false, false);
      }
    },
    {
      noAck: false
    }
  );
}

startConsumer().catch(err => {
  console.error('[FATAL] Unable to start payment consumer:', err);
  process.exit(1);
});